// ── Resolve user input: URL → accountId, email → mark for search, raw → passthrough ──
function resolveUserInput(val) {
  if (!val) return { accountId: '', needsSearch: false, searchQuery: '' };
  val = val.trim();
  // Atlassian profile URL: extract and decode the ID after /people/
  const peopleMatch = val.match(/\/people\/([^?/]+)/);
  if (peopleMatch) return { accountId: decodeURIComponent(peopleMatch[1]), needsSearch: false, searchQuery: '' };
  // Email: needs API search
  if (val.includes('@')) return { accountId: '', needsSearch: true, searchQuery: val };
  // Raw accountId
  return { accountId: val, needsSearch: false, searchQuery: '' };
}

const body = $input.first().json.body;
const assigneeInput = resolveUserInput(body.assignee || '');
const reporterInput = resolveUserInput(body.reporter || '');

// Build search queries for any emails that need resolving
const searches = [];
if (assigneeInput.needsSearch) searches.push({ field: 'assignee', query: assigneeInput.searchQuery });
if (reporterInput.needsSearch) searches.push({ field: 'reporter', query: reporterInput.searchQuery });

return [{ json: {
  body,
  assigneeId: assigneeInput.accountId,
  reporterId: reporterInput.accountId,
  searches,
  needsSearch: searches.length > 0
} }];

const prev = $('Extract User IDs').first().json;
const searchResults = $input.first().json;
let assigneeId = prev.assigneeId;
let reporterId = prev.reporterId;

// Map search results back to the right field
const searches = prev.searches || [];
const results = Array.isArray(searchResults) ? searchResults : [searchResults];
for (const s of searches) {
  const found = results.find(r => r.emailAddress === s.query || r.displayName === s.query);
  const resolvedId = (results.length > 0 && results[0].accountId) ? results[0].accountId : '';
  if (s.field === 'assignee' && !assigneeId) assigneeId = found?.accountId || resolvedId;
  if (s.field === 'reporter' && !reporterId) reporterId = found?.accountId || resolvedId;
}
// If two different emails, second one needs separate search — for simplicity use first result
// (Full implementation would do two searches)
if (searches.length > 1 && !reporterId) {
  reporterId = assigneeId; // fallback: same user if only one search was done
}

return [{ json: { body: prev.body, assigneeId, reporterId } }];

// ── Markdown-to-ADF converter ──
function mdToAdf(md) {
  const lines = md.split('\n');
  const nodes = [];
  let i = 0;
  function inlineToAdf(text) {
    const parts = [];
    const regex = /(\*\*(.+?)\*\*|\*(.+?)\*|`([^`]+)`|\[([^\]]+)\]\(([^)]+)\))/g;
    let last = 0; let m;
    while ((m = regex.exec(text)) !== null) {
      if (m.index > last) parts.push({ type: 'text', text: text.slice(last, m.index) });
      if (m[2]) parts.push({ type: 'text', text: m[2], marks: [{ type: 'strong' }] });
      else if (m[3]) parts.push({ type: 'text', text: m[3], marks: [{ type: 'em' }] });
      else if (m[4]) parts.push({ type: 'text', text: m[4], marks: [{ type: 'code' }] });
      else if (m[5] && m[6]) parts.push({ type: 'text', text: m[5], marks: [{ type: 'link', attrs: { href: m[6] } }] });
      last = m.index + m[0].length;
    }
    if (last < text.length) parts.push({ type: 'text', text: text.slice(last) });
    if (parts.length === 0 && text) parts.push({ type: 'text', text });
    return parts;
  }
  while (i < lines.length) {
    const line = lines[i];
    if (line.startsWith('```')) {
      const lang = line.slice(3).trim() || null; const codeLines = []; i++;
      while (i < lines.length && !lines[i].startsWith('```')) { codeLines.push(lines[i]); i++; } i++;
      const cb = { type: 'codeBlock', content: [{ type: 'text', text: codeLines.join('\n') }] };
      if (lang) cb.attrs = { language: lang }; nodes.push(cb); continue;
    }
    const hm = line.match(/^(#{1,6}) (.+)$/);
    if (hm) { nodes.push({ type: 'heading', attrs: { level: hm[1].length }, content: inlineToAdf(hm[2]) }); i++; continue; }
    if (line.match(/^---+$/)) { nodes.push({ type: 'rule' }); i++; continue; }
    if (line.startsWith('> ')) { const ql = []; while (i < lines.length && lines[i].startsWith('> ')) { ql.push(lines[i].slice(2)); i++; } nodes.push({ type: 'blockquote', content: [{ type: 'paragraph', content: inlineToAdf(ql.join(' ')) }] }); continue; }
    if (line.match(/^[-*] /)) { const items = []; while (i < lines.length && lines[i].match(/^[-*] /)) { items.push({ type: 'listItem', content: [{ type: 'paragraph', content: inlineToAdf(lines[i].replace(/^[-*] /, '')) }] }); i++; } nodes.push({ type: 'bulletList', content: items }); continue; }
    if (line.match(/^\d+[.)]/)) { const items = []; while (i < lines.length && lines[i].match(/^\d+[.)]/)) { items.push({ type: 'listItem', content: [{ type: 'paragraph', content: inlineToAdf(lines[i].replace(/^\d+[.)] ?/, '')) }] }); i++; } nodes.push({ type: 'orderedList', content: items }); continue; }
    if (line.match(/^\|.+\|$/) && i + 1 < lines.length && lines[i+1].match(/^\|[-| :]+\|$/)) {
      const hc = line.split('|').filter(c => c.trim()).map(c => ({ type: 'tableHeader', content: [{ type: 'paragraph', content: inlineToAdf(c.trim()) }] }));
      const rows = [{ type: 'tableRow', content: hc }]; i += 2;
      while (i < lines.length && lines[i].match(/^\|.+\|$/)) { rows.push({ type: 'tableRow', content: lines[i].split('|').filter(c => c.trim()).map(c => ({ type: 'tableCell', content: [{ type: 'paragraph', content: inlineToAdf(c.trim()) }] })) }); i++; }
      nodes.push({ type: 'table', attrs: { isNumberColumnEnabled: false, layout: 'default' }, content: rows }); continue;
    }
    if (!line.trim()) { i++; continue; }
    nodes.push({ type: 'paragraph', content: inlineToAdf(line) }); i++;
  }
  return { type: 'doc', version: 1, content: nodes.length > 0 ? nodes : [{ type: 'paragraph', content: [{ type: 'text', text: ' ' }] }] };
}

function parseMarkdown(md) {
  const lines = md.split('\n');
  const titleLine = lines.find(l => l.startsWith('# '));
  const title = titleLine ? titleLine.replace(/^# /, '') : 'Untitled';
  const titleIdx = lines.indexOf(titleLine);
  const knownSections = ['Acceptance Criteria', 'Priority', 'Estimate', 'Component', 'Labels'];
  const bodyLines = [];
  for (let j = (titleIdx >= 0 ? titleIdx + 1 : 0); j < lines.length; j++) {
    if (lines[j].startsWith('## ') && knownSections.some(s => lines[j] === '## ' + s)) break;
    bodyLines.push(lines[j]);
  }
  while (bodyLines.length && !bodyLines[0].trim()) bodyLines.shift();
  while (bodyLines.length && !bodyLines[bodyLines.length - 1].trim()) bodyLines.pop();
  const bodyMarkdown = bodyLines.join('\n');
  function getSection(heading) { const start = lines.findIndex(l => l === '## ' + heading); if (start === -1) return []; const out = []; for (let j = start + 1; j < lines.length; j++) { if (lines[j].startsWith('## ')) break; if (lines[j].trim()) out.push(lines[j]); } return out; }
  function getField(heading) { const s = getSection(heading); return s.length ? s[0].trim() : ''; }
  const criteria = getSection('Acceptance Criteria').filter(l => l.startsWith('- ')).map(l => l.replace(/^- /, ''));
  const priority = getField('Priority') || ($env.JIRA_DEFAULT_PRIORITY || 'Medium');
  const component = getField('Component');
  const labelsStr = getField('Labels');
  const labels = ['ai-generated'];
  if (labelsStr) labels.push(...labelsStr.split(',').map(l => l.trim()).filter(Boolean));
  return { title, bodyMarkdown, criteria, priority, component, labels };
}

function buildJiraFields(parsed, issueType, parentKey, formComponent, assignee, reporter) {
  let fullMd = parsed.bodyMarkdown || '';
  if (parsed.criteria.length > 0) { if (fullMd) fullMd += '\n\n'; fullMd += '## Acceptance Criteria\n'; for (const c of parsed.criteria) fullMd += '- ' + c + '\n'; }
  const fields = { summary: parsed.title, description: mdToAdf(fullMd), priority: { name: parsed.priority }, labels: parsed.labels };
  const comp = parsed.component || formComponent || ($env.JIRA_DEFAULT_COMPONENT || '');
  if (comp) fields.components = [{ name: comp }];
  if (assignee) fields.assignee = { accountId: assignee };
  if (reporter) fields.reporter = { accountId: reporter };
  if (parentKey) fields.parent = { key: parentKey };
  return fields;
}

function extractKey(input) {
  if (!input) return '';
  const browseMatch = input.match(/\/browse\/([A-Z]+-\d+)/);
  if (browseMatch) return browseMatch[1];
  if (input.match(/^[A-Z]+-\d+$/)) return input;
  return input.trim();
}

const prev = $input.first().json;
const body = prev.body;
const assigneeId = prev.assigneeId || '';
const reporterId = prev.reporterId || '';
const epicMarkdown = body.epicMarkdown || '';
const taskMarkdowns = body.taskMarkdowns || [];
const epicKey = extractKey(body.epicKey || '');
const taskKeys = (body.taskKeys || []).map(k => extractKey(k));
const taskAssignees = body.taskAssignees || [];
const formComponent = body.component || '';

const epicParsed = parseMarkdown(epicMarkdown);
const epicIssueType = $env.JIRA_EPIC_ISSUE_TYPE || 'Epic';

let epicApiBody, epicMethod, epicUrl;
if (epicKey) {
  epicMethod = 'PUT';
  epicUrl = $env.JIRA_BASE_URL + '/rest/api/3/issue/' + epicKey;
  epicApiBody = { fields: buildJiraFields(epicParsed, epicIssueType, null, formComponent, assigneeId, reporterId) };
} else {
  epicMethod = 'POST';
  epicUrl = $env.JIRA_BASE_URL + '/rest/api/3/issue';
  const fields = buildJiraFields(epicParsed, epicIssueType, null, formComponent, assigneeId, reporterId);
  fields.project = { key: $env.JIRA_PROJECT_KEY };
  fields.issuetype = { name: epicIssueType };
  epicApiBody = { fields };
}

return [{ json: { epicApiBody, epicMethod, epicUrl, epicKey, epicTitle: epicParsed.title, taskMarkdowns, taskKeys, taskAssignees, isUpdate: !!epicKey, formComponent, assigneeId, reporterId } }];

