const rawResponse = $input.first().json;
let epicResponse = {};
try { const txt = rawResponse.data || rawResponse.body || (typeof rawResponse === 'string' ? rawResponse : ''); if (txt && typeof txt === 'string' && txt.trim()) epicResponse = JSON.parse(txt); else if (rawResponse.key) epicResponse = rawResponse; } catch(e) { epicResponse = rawResponse; }
const prev = $('Parse Epic Markdown').first().json;
const epicKey = prev.epicKey || epicResponse.key;
const epicTitle = prev.epicTitle;
const taskMarkdowns = prev.taskMarkdowns || [];
const taskKeys = prev.taskKeys || [];
const taskAssignees = prev.taskAssignees || [];
const formComponent = prev.formComponent || '';
const assigneeId = prev.assigneeId || '';
const reporterId = prev.reporterId || '';
const storyType = $env.JIRA_STORY_ISSUE_TYPE || 'Story';
const jiraBase = $env.JIRA_BASE_URL;

if (taskMarkdowns.length === 0) return [{ json: { epicKey, epicTitle, noTasks: true } }];

return taskMarkdowns.map((md, idx) => {
  const parsed = parseMarkdown(md);
  const existingKey = taskKeys[idx] || '';
  // Per-task assignee: resolve URL if needed, otherwise use form default
  let taskAssignee = taskAssignees[idx] || '';
  if (taskAssignee) {
    const pm = taskAssignee.match(/\/people\/([^?/]+)/);
    if (pm) taskAssignee = decodeURIComponent(pm[1]);
    else if (taskAssignee.includes('@')) taskAssignee = ''; // can't resolve per-task emails in this node
  }
  if (!taskAssignee) taskAssignee = assigneeId;
  let method, url, apiBody;
  if (existingKey) {
    method = 'PUT'; url = jiraBase + '/rest/api/3/issue/' + existingKey;
    apiBody = { fields: buildJiraFields(parsed, storyType, epicKey, formComponent, taskAssignee, reporterId) };
  } else {
    method = 'POST'; url = jiraBase + '/rest/api/3/issue';
    const fields = buildJiraFields(parsed, storyType, epicKey, formComponent, taskAssignee, reporterId);
    fields.project = { key: $env.JIRA_PROJECT_KEY }; fields.issuetype = { name: storyType };
    apiBody = { fields };
  }
  return { json: { apiBody, method, url, taskTitle: parsed.title, epicKey, epicTitle, existingKey } };
});

const prev = $('Prepare Tasks').first().json;
const epicKey = prev.epicKey;
const epicTitle = prev.epicTitle;
const jiraBase = $env.JIRA_BASE_URL;
const allTasks = $('Prepare Tasks').all();
const allResults = $input.all();
const tasks = allTasks.map((t, i) => {
  const raw = allResults[i]?.json || {};
  let result = {};
  try { const txt = raw.data || raw.body || (typeof raw === 'string' ? raw : ''); if (txt && typeof txt === 'string' && txt.trim()) result = JSON.parse(txt); else if (raw.key) result = raw; } catch(e) { result = raw; }
  const key = result.key || t.json.existingKey;
  return { key, title: t.json.taskTitle, url: jiraBase + '/browse/' + key, action: t.json.existingKey ? 'updated' : 'created' };
});
return [{ json: { success: true, epic: { key: epicKey, title: epicTitle, url: jiraBase + '/browse/' + epicKey, action: $('Parse Epic Markdown').first().json.isUpdate ? 'updated' : 'created' }, tasks, taskCount: tasks.length } }];

